#include <iostream>
#include <string>
#include <algorithm>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;
    int n = (int)s.size();

    // dp[i][j] = minimum insertions for substring s[i..j] (inclusive)
    vector<vector<int>> dp(n, vector<int>(n, 0));

    // len = 1 -> 0 insertions already palindrome
    // Fill increasing lengths
    for (int len = 2; len <= n; ++len) {
        for (int i = 0; i + len - 1 < n; ++i) {
            int j = i + len - 1;
            if (s[i] == s[j]) {
                dp[i][j] = dp[i+1][j-1];
            } else {
                dp[i][j] = 1 + min(dp[i+1][j], dp[i][j-1]);
            }
        }
    }

    cout << dp[0][n-1] << '\n';

    return 0;
}
